import React, { useState } from 'react';
import PreRecord from './PreRecord';
import WhileRecord from './WhileRecord';
import PlayBack from './PlayBack';
import Share from './Share';
import SaveConfirm from './SaveConfirm';

function RecordPage() {
  const [screen, setScreen] = useState('pre');
  const [recordedTime, setRecordedTime] = useState(0);

  const handleRecord = () => setScreen('while');

  const handlePause = (elapsed) => {
    setRecordedTime(elapsed);
    setScreen('playback');
  };

  const handleSave = (elapsed) => {
    if (elapsed !== undefined) setRecordedTime(elapsed);
    setScreen('share');
  };

  const handleContinue = () => setScreen('while');

  const handleRestart = () => {
    setRecordedTime(0);
    setScreen('pre');
  };

  const handleShare = () => setScreen('save');

  const handleNew = () => {
    setRecordedTime(0);
    setScreen('pre');
  };

  switch (screen) {
    case 'pre':
      return <PreRecord onRecord={handleRecord} />;
    case 'while':
      return <WhileRecord onPause={handlePause} onSave={handleSave} />;
    case 'playback':
      return <PlayBack currentTime={recordedTime} onContinue={handleContinue} onRestart={handleRestart} onSave={handleSave} />;
    case 'share':
      return <Share currentTime={recordedTime} onShare={handleShare} onNew={handleNew} />;
    case 'save':
      return <SaveConfirm currentTime={recordedTime} onNew={handleNew} />;
    default:
      return <PreRecord onRecord={handleRecord} />;
  }
}

export default RecordPage;
